hitMacro.command:
const amount  = -((Number(scope.spellDamageDice ?? 1) || 1) * 5);
const targets = scope.targets ?? [];
if (!targets.length) return ui.notifications.warn("Tempo: no target.");
const duration = scope.isCritical ? { seconds: 60 } : {};
for (const t of targets) {
  const a = t.actor ?? t; if (!a) continue;
  const npc = typeof a.system.speed !== "object";
  await a.createEmbeddedDocuments("ActiveEffect", [{
    name: `Tempo (${amount} ft)`,
    img: "icons/magic/time/clock-stopwatch-white-blue.webp",
    duration,
    changes: [{ key: npc ? "system.speed" : "system.speed.bonus", mode: CONST.ACTIVE_EFFECT_MODES.ADD, value: String(amount) }],
    flags: { vagabond: { tempo: true } },
  }]);
}
ui.notifications.info(`Tempo: ${amount} ft on ${targets.length} target(s).`);
